#include<cstdio>
#include<cstdlib>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=30010;int n,Mod,L,R,Q,ans[N],a[N],cpt,f[N],P[N],p,cnt[N];
struct Nd{int l,r,idx;}q[N];LL res;inline void DN(int &x){x>=Mod?x-=Mod:0;}
inline int bnd(const int &k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
int main()
{
//	FIN("data.in");FOUT("mine.out");
	n=read();Mod=read();f[1]=f[2]=(Mod==1?0:1); rep(3,n,i)DN(f[i]=f[i-1]+f[i-2]);
	rep(1,n,i)P[i]=a[i]=read();std::sort(P+1,P+n+1);p=std::unique(P+1,P+n+1)-P-1;rep(1,n,i)a[i]=bnd(a[i]);
	Q=read();rep(1,Q,i)q[i].l=read(),q[i].r=read(),q[i].idx=i;
	std::sort(q+1,q+Q+1,[&](const Nd &x,const Nd &y){return (x.l>>8)==(y.l>>8)?((x.l>>8)&1?x.r>y.r:x.r<y.r):x.l<y.l;});
	L=q[1].l;R=L-1;rep(1,Q,i)
	{
		while(R<q[i].r)++cnt[a[++R]];while(L>q[i].l)++cnt[a[--L]];
		while(R>q[i].r)--cnt[a[R--]];while(L<q[i].l)--cnt[a[L++]];
		LL res=0;int cpt=0;rep(1,p,i)if(cnt[i])res+=1ll*f[++cpt]*P[i];ans[q[i].idx]=res%Mod;
	}
	rep(1,Q,i)printf("%d\n",ans[i]);return 0;
}
